const ships     = $('Get Ships').first().json.data || [];
const contracts = $input.first().json.data || [];

const now        = Date.now();
const staticData = $getWorkflowStaticData('global');

const ASTEROID     = 'X1-UX96-B12';
const DELIVER_WP   = 'X1-UX96-H52';
const FUEL_STATION = 'X1-UX96-B6';
const MIN_FUEL     = 280;

const activeC  = contracts.find(c => c.accepted && !c.fulfilled);
const pendingC = contracts.find(c => !c.accepted && !c.fulfilled);

const term     = activeC?.terms?.deliver?.[0];
const tradeSym = term?.tradeSymbol || 'ALUMINUM_ORE';
const needed   = (term?.unitsRequired || 0) - (term?.unitsFulfilled || 0);

// ── Role classification ─────────────────────────────────────────────────
// Returns 'hauler', 'miner', or null (skip)
function getRole(ship) {
  const frame = ship.frame?.symbol || '';
  // Skip starter probe and satellites — no mounts, no cargo, no use
  if (frame.includes('PROBE') || frame.includes('SATELLITE')) return null;
  // Frigate = primary hauler (does full mine+deliver loop)
  if (frame.includes('FRIGATE')) return 'hauler';
  // Any ship with a mining laser = miner (also does full loop for now)
  const hasLaser = (ship.mounts || []).some(m => m.symbol?.includes('MINING_LASER'));
  if (hasLaser) return 'miner';
  // Unknown frame without laser — skip until we know what to do with it
  return null;
}

// Shared per-tick flags — only one ship performs each coordination action
let contractAccepted = false;

function decide(ship) {
  const nav        = ship.nav;
  const cargo      = ship.cargo;
  const fuel       = ship.fuel;
  const status     = nav.status;
  const wp         = nav.waypointSymbol;
  const flightMode = nav.flightMode || 'CRUISE';
  const sym        = ship.symbol;

  const cdExp = ship.cooldown?.expiration ? new Date(ship.cooldown.expiration).getTime() : 0;
  if (cdExp > now) return {action:'on_cooldown', ship:sym, remainMs:cdExp - now};

  if (status === 'IN_TRANSIT') {
    const arr = new Date(nav.route?.arrival).getTime();
    if (arr > now) return {action:'in_transit', ship:sym, eta:nav.route.arrival};
  }

  // Accept next contract — only one ship does this per tick
  if (!activeC && pendingC && !contractAccepted) {
    contractAccepted = true;
    return {action:'accept_contract', ship:sym, contractId:pendingC.id};
  }

  // No contract — jettison any cargo then idle
  if (!activeC) {
    if (cargo.units > 0)
      return cargo.inventory.map(i => ({action:'jettison', ship:sym, symbol:i.symbol, units:i.units}));
    return {action:'idle', ship:sym, status, wp, reason:'awaiting_contract'};
  }

  const haveOre  = cargo.inventory.find(i => i.symbol === tradeSym)?.units || 0;
  const cargoPct = cargo.capacity > 0 ? cargo.units / cargo.capacity : 0;
  const fuelFull = fuel.current >= fuel.capacity * 0.95;
  const fuelPct  = fuel.capacity > 0 ? fuel.current / fuel.capacity : 1;

  // ── DELIVER ─────────────────────────────────────────────────────────────
  if (haveOre > 0) {
    const shouldDeliver = wp === DELIVER_WP || cargoPct >= 0.8 || haveOre >= needed;
    if (shouldDeliver) {

      if (wp === DELIVER_WP) {
        if (status === 'IN_ORBIT') return {action:'dock', ship:sym};
        if (status === 'DOCKED')   return {action:'deliver', ship:sym,
            contractId:activeC.id, tradeSymbol:tradeSym, units:haveOre};
      }

      if (wp === FUEL_STATION) {
        if (status === 'IN_ORBIT') {
          if (fuelFull) return {action:'navigate', ship:sym, waypoint:DELIVER_WP, reason:'deliver'};
          return {action:'dock', ship:sym};
        }
        if (status === 'DOCKED') {
          if (!fuelFull)              return {action:'refuel', ship:sym};
          if (flightMode === 'DRIFT') return {action:'set_cruise', ship:sym};
          return {action:'orbit', ship:sym};
        }
      }

      if (status === 'DOCKED') return {action:'orbit', ship:sym};
      if (status === 'IN_ORBIT') {
        if (fuel.current < MIN_FUEL) {
          if (flightMode !== 'DRIFT') return {action:'set_drift', ship:sym};
          return {action:'navigate', ship:sym, waypoint:FUEL_STATION, reason:'refuel'};
        }
        return {action:'navigate', ship:sym, waypoint:DELIVER_WP, reason:'deliver'};
      }
    }
  }

  // ── JETTISON JUNK ───────────────────────────────────────────────────────
  const junk = cargo.inventory.filter(i => i.symbol !== tradeSym);
  if (cargoPct >= 0.7 && junk.length > 0)
    return junk.map(i => ({action:'jettison', ship:sym, symbol:i.symbol, units:i.units}));

  // ── NAVIGATE TO ASTEROID ────────────────────────────────────────────────
  if (wp !== ASTEROID) {
    if (status === 'DOCKED') {
      if (wp === FUEL_STATION && !fuelFull) return {action:'refuel', ship:sym};
      if (fuelPct < 0.2)              return {action:'refuel', ship:sym};
      if (flightMode === 'DRIFT')     return {action:'set_cruise', ship:sym};
      return {action:'orbit', ship:sym};
    }
    if (status === 'IN_ORBIT') {
      if (fuel.current < MIN_FUEL) {
        if (wp === FUEL_STATION)      return {action:'dock', ship:sym};
        if (flightMode !== 'DRIFT')   return {action:'set_drift', ship:sym};
        return {action:'navigate', ship:sym, waypoint:FUEL_STATION, reason:'refuel'};
      }
      return {action:'navigate', ship:sym, waypoint:ASTEROID, reason:'mine'};
    }
  }

  // ── AT ASTEROID ─────────────────────────────────────────────────────────
  if (wp === ASTEROID && status === 'IN_ORBIT') {
    const survey = staticData.survey;
    const surveyValid = survey && new Date(survey.expiration).getTime() > now;
    if (!surveyValid) return {action:'survey', ship:sym};
    return {action:'mine_survey', ship:sym, survey};
  }

  if (wp === ASTEROID && status === 'DOCKED') return {action:'orbit', ship:sym};

  return {action:'idle', ship:sym, status, wp};
}

// ── MAIN LOOP ────────────────────────────────────────────────────────────
const actions = [];
for (const ship of ships) {
  const role = getRole(ship);
  if (!role) continue;               // skip probes / unknown frames

  const result = decide(ship);
  if (!result) continue;
  // decide() may return an array for multi-item actions (jettison per cargo type)
  if (Array.isArray(result)) {
    for (const item of result) actions.push({json: item});
  } else {
    actions.push({json: result});
  }
}

return actions.length > 0 ? actions : [{json:{action:'idle', reason:'no_active_ships'}}];

const staticData = $getWorkflowStaticData('global');
const result = $input.first().json;
const surveys = result.data?.surveys || [];

// Prefer survey that has contract ore deposits
const contractOre = 'ALUMINUM_ORE';
const best = surveys.find(s => s.deposits?.some(d => d.symbol === contractOre)) || surveys[0];

if (best) {
  staticData.survey = best;
  const ores = best.deposits.map(d => d.symbol).join(', ');
  return [{json:{stored:true, signature:best.signature, ores, expiration:best.expiration}}];
}
return [{json:{stored:false}}];

